INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '82a4ba4d-af5a-484e-9a9d-c0c747b61a98',
  '00000000-0000-0000-0000-000000000001',
  $escape$jwt — Symmetric vs Asymmetric Signing: When to Use Each$escape$,
  $escape$When signing a JWT, you can choose between symmetric and asymmetric algorithms. Symmetric algorithms, like HS256, use the same secret key for signing and verification. Asymmetric algorithms, like RS256, use a public key for signing and a private key for verification. Symmetric signing is faster and more secure for short-term use cases, like session management. Asymmetric signing provides better long-term security and can be used for authenticating users. If you're using a third-party service for JWT verification, stick with symmetric signing.$escape$,
  NULL,
  NULL,
