INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9595d314-b726-4206-ab7a-2aafb6d24ed3',
  '00000000-0000-0000-0000-000000000001',
  $escape$jwt - Authorization Code Flow with PKCE: A Secure Approach$escape$,
  $escape$When implementing OAuth 2.0 with jwt, the authorization code flow with Proof Key for Code Exchange (PKCE) is a secure alternative to implicit flow. PKCE mitigates authorization code interception attacks by generating a cryptographically secure code verifier and challenge. To use PKCE with jwt, generate a code verifier, encode it to a challenge, and include it in the authorization request. The authorization server will then verify the code verifier and challenge to ensure the authorization code is not intercepted.$escape$,
  NULL,
  NULL,
