INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f6bfa22c-fb47-4476-afb8-e9972ba8458a',
  '00000000-0000-0000-0000-000000000001',
  $escape$jwt - ID Tokens vs Access Tokens: Choosing the Right Strategy$escape$,
  $escape$When implementing OpenID Connect (OIDC) with JSON Web Tokens (JWT), you'll encounter two types of tokens: ID tokens and access tokens. ID tokens contain the user's profile information, while access tokens grant access to protected resources. OIDC's UserInfo endpoint retrieves the user's profile from the ID token, which can be validated using the JWT library. To discover the OIDC configuration, use the .well-known/openid-configuration endpoint, which returns a JSON object containing the necessary parameters. When using JWT to validate the ID token, ensure to verify the token's signature and payload.$escape$,
  $escape$const jwksClient = require('jwks-rsa');
const client = new jwksClient({ jwksUri: 'https://example.com/.well-known/jwks.json' });
const token = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...';
client.getSigningKey(token, (err, key) => {
  if (err) return console.error(err);
  const signingKey = key.getPublicKey();
  const decoded = jwt.verify(token, signingKey);
  console.log(decoded); // User's profile information
});$escape$,
  $escape$javascript$escape$,
