INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '97a3daa3-7cd0-4054-abcb-901aa64d11c1',
  '00000000-0000-0000-0000-000000000001',
  $escape$jwt — 3 Common Cryptographic Mistakes to Avoid$escape$,
  $escape$When using JSON Web Tokens (JWT) for authentication, developers often make mistakes with password hashing and encryption. Firstly, never use MD5 or SHA1 for password hashing in JWT. Instead, use a library like `jsonwebtoken` that supports algorithms like `HS256` or `RS256`. Avoid using ECB mode in JWT, as it's vulnerable to padding oracle attacks. Lastly, never roll your own crypto, always rely on established libraries like `jsonwebtoken`.$escape$,
  NULL,
  NULL,
