INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '403b28b5-0d82-4205-88ae-a23aaf7ecc5f',
  '00000000-0000-0000-0000-000000000001',
  $escape$jwt: When to Choose Signed vs Encrypted Tokens$escape$,
  $escape$When authenticating APIs, developers choose between API keys, OAuth tokens, or JSON Web Tokens (JWTs). JWTs are particularly useful when you need to convey user identity, permissions, and additional claims. However, JWTs can be vulnerable to token theft, especially when transmitted in plain text. In such cases, consider using JWT with digital signatures (e.g., HMAC SHA-256) for authenticity verification. For confidentiality, use JWT with encryption (e.g., JWE) and a shared secret key. When transmitting sensitive data, always prefer JWE over JWS.$escape$,
  NULL,
  NULL,
